local UIResultAward = class("UIResultAward", IGUILayout)
local AwardType = {
    [1] = "coin",
    [2] = "gold",
    [3] = "muscle",
    [4] = "score",
}
local delayTime = 0
local Animation = {
    beginShowUI       = {status = 0, time = delayTime + 0}, --默认初始状态
    showTitleBg1      = {status = 1, time = delayTime + 300}, --火焰背景
    showTitleBg2      = {status = 2, time = delayTime + 500}, --段位背景，数字，按钮，光效，线
    showTitleBg3      = {status = 3, time = delayTime + 800}, --奖杯
    showItemEffect    = {status = 4, time = delayTime + 1300}, --奖励图标闪动
    showItemNumScroll = {status = 5, time = delayTime + 1800}, --奖励数字滚动
    uiPause           = {status = 6, time = delayTime + 0},--暂停（等待按钮状态time = 0）
    endHideUI         = {status = 7, time = delayTime + 0},--隐藏文字，按钮，光效
    moveTitleAndItem  = {status = 8, time = delayTime + 1000},--标题和奖励上下分散
    showNextUI        = {status = 9, time = delayTime + 0},--显示计分板
}

function UIResultAward:onLoad()
    self:initData()
    self:initUI()
    self:initEvent()
end

function UIResultAward:initData()
    self.time = 0
    self.aniBegin = false
    self.aniStatus = Animation.beginShowUI.status
    self.rankDate = {}
    self.numDate = {}
    self.titleBoxR_star_Area = {}
    self.titleBoxR_end_Area = {}
    self.itemBoxR_star_Area = {}
    self.itemBoxR_end_Area = {}
end

function UIResultAward:initUI()
    self.siTitleBox = self:getChildWindow("LSChampionShipResultAward-TitleBox", GUIType.StaticImage)
    self.titleBoxR_star_Area = self:getUIR_Area(self.siTitleBox)
    self.titleBoxR_end_Area = self:setUI_End_R_Area(self.titleBoxR_star_Area, -0.4)
    self.siTitleBg ={}
    self.stTitleText ={}
    self.eivTitleEffect ={}
    for i=1,3 do
        self.siTitleBg[i] = self:getChildWindow("LSChampionShipResultAward-TitleBg"..i, GUIType.StaticImage)
