        self.siTitleBg[i]:SetImage("")
        self.stTitleText[i] = self:getChildWindow("LSChampionShipResultAward-TitleText"..i, GUIType.StaticText)
        self.stTitleText[i]:SetVisible(false)
        self.eivTitleEffect[i] = self:getChildWindow("LSChampionShipResultAward-TitleEffect"..i, GUIType.EffectViewOfObtainment)
        self.eivTitleEffect[i]:SetVisible(false)
    end

    self.siItemBox = self:getChildWindow("LSChampionShipResultAward-ItemBox", GUIType.StaticImage)
    self.itemBoxR_star_Area = self:getUIR_Area(self.siItemBox)
    self.itemBoxR_end_Area = self:setUI_End_R_Area(self.itemBoxR_star_Area, 0.6)
    self.siItemBg = {}
    self.stItemNum = {}
    self.eivItemEffect = {}
    for i=1,#AwardType do
        self.siItemBg[i] = self:getChildWindow("LSChampionShipResultAward-Item-Bg"..i, GUIType.StaticImage)
        self.siItemBg[i]:SetImage("")
        -- self.siItemBox:AddChildWindow(self.siItemBg[i])
        self.stItemNum[i] = self:getChildWindow("LSChampionShipResultAward-Item-Num"..i, GUIType.StaticText)
        self.stItemNum[i]:SetVisible(false)
        self.eivItemEffect[i] = self:getChildWindow("LSChampionShipResultAward-effect"..i, GUIType.EffectViewOfObtainment)
        self.eivItemEffect[i]:SetVisible(false)
    end

    self.btnSure = self:getChildWindow("LSChampionShipResultAward-BtnSure" ,GUIType.Button)
    self.btnSure:SetVisible(false)
    self.btnSure:SetText(Lang:getString("gui_btn_sure"))

    self.stGetText = self:getChildWindow("LSChampionShipResultAward-GetText", GUIType.StaticText)
    self.stGetText:SetVisible(false)
    self.stGetText:SetText(Lang:getString("gui_have_get_award"))

    self.siBgEffec = self:getChildWindow("LSChampionShipResultAward-BgEffect", GUIType.StaticImage)
    self.siBgEffec:SetVisible(false)
    self.siLine = {}
    for i=1,2 do
        self.siLine[i] = self:getChildWindow("LSChampionShipResultAward-line"..i, GUIType.StaticImage)
        self.siLine[i]:SetVisible(false)
