end

function UIResultAward:initEvent()
    self:registerEvent(S2CLSShowResultAward, function(data)
        self:ShowResultAward(data)
    end)

    self.btnSure:registerEvent(GUIEvent.ButtonClick, function ()
        self:onClickSure()
    end)
end

function UIResultAward:onTick(frameTime)
    if not self:isShow() or not self.aniBegin then
        self.time = 0
        return
    end
    self.time = self.time + frameTime
    self:onUpdate()

end

function UIResultAward:onUpdate()
    if self.aniStatus == Animation.beginShowUI.status then
        if self.time > Animation.beginShowUI.time then
            self.aniStatus = Animation.showTitleBg1.status
        end
    elseif self.time < Animation.showTitleBg1.time then
        if self.aniStatus == Animation.showTitleBg1.status then
            self:showTitleEffect(1)
            self.aniStatus = Animation.showTitleBg2.status
        end
    elseif self.time < Animation.showTitleBg2.time then
        if self.aniStatus == Animation.showTitleBg2.status then
            self:showTitleBg(1)
            self:showTitleEffect(2)
            self:showTitleTextAndBtn()
            self.aniStatus = Animation.showTitleBg3.status
        end
    elseif self.time < Animation.showTitleBg3.time then
        if self.aniStatus == Animation.showTitleBg3.status then
            self:showTitleBg(2)
            self:showTitleEffect(3)
            self.aniStatus = Animation.showItemEffect.status
        end
    elseif self.time < Animation.showItemEffect.time then
        if self.aniStatus == Animation.showItemEffect.status then
            self:showTitleBg(3)
            self:showItemEffect()
            self.aniStatus = Animation.showItemNumScroll.status
        end
    elseif self.time < Animation.showItemNumScroll.time then
        if self.aniStatus == Animation.showItemNumScroll.status then
            self:showItemBg()
            self:showItemNumScroll()
            self.aniStatus = Animation.uiPause.status
            self.aniBegin = false
        end
    end
    if  self.aniStatus == Animation.endHideUI.status then
            self:endHideUI()
            self.aniStatus = Animation.moveTitleAndItem.status
            self.time = 0
    elseif self.aniStatus == Animation.moveTitleAndItem.status then
            local T = Animation.moveTitleAndItem.time
            if self.time <= T then
                local progress = 1 - (T - self.time)/T
                -- if progress >= 0.9 then
                --     progress =1
                -- end
                self:moveTitleAndItem(progress)
            else
                self.aniStatus = Animation.showNextUI.status
            end
    elseif self.aniStatus == Animation.showNextUI.status then
        self:showNextUI()
        self.aniBegin = false
    end
end

function UIResultAward:showTitleEffect(i)
    -- LogUtil.log("--- showTitleEffect ---"..self.time)
    self.eivTitleEffect[i]:SetImage("set:LSChampionShip_ResultAward.json image:title"..4-i)
    self.eivTitleEffect[i]:SetVisible(true)
end

function UIResultAward:showTitleBg(i)
    -- LogUtil.log("--- showTitleBg ---"..self.time)
    self.siTitleBg[i]:SetImage("set:LSChampionShip_ResultAward.json image:title"..4-i)
    -- self.siTitleBg[i]:SetVisible(true)
    self.eivTitleEffect[i]:SetVisible(false)
end

function UIResultAward:showTitleTextAndBtn()
    -- LogUtil.log("--- showTitleTextAndBtn ---"..self.time)
    for i=1,3 do
        self.stTitleText[i]:SetVisible(true)
    end
    for i=1,2 do
        self.siLine[i]:SetVisible(true)
    end
    self.stGetText:SetVisible(true)
    self.btnSure:SetVisible(true)
    self.siBgEffec:SetVisible(true)
end

function UIResultAward:showItemEffect()
    -- LogUtil.log("--- showItemEffect ---"..self.time)
    for i=1,#AwardType do
        self.eivItemEffect[i]:SetImage("set:LSChampionShip_ResultAward.json image:"..AwardType[i])
        self.eivItemEffect[i]:SetVisible(true)
    end
end

function UIResultAward:showItemBg()
    -- LogUtil.log("--- showItemBg ---"..self.time)
    for i=1,#AwardType do
        self.siItemBg[i]:SetImage("set:LSChampionShip_ResultAward.json image:"..AwardType[i])
        self.siItemBg[i]:SetVisible(true)
        self.eivItemEffect[i]:SetVisible(false)
    end
end

function UIResultAward:showItemNumScroll()
    -- LogUtil.log("--- showItemNumScroll ---"..self.time)
    for k1,v1 in pairs(AwardType) do
        for k2,v2 in pairs(self.numDate) do
            if tostring(v1) == tostring(k2) then
                self.stItemNum[k1]:SetScrollEffect(1000)
                if v2 > 9999 then
                    self.stItemNum[k1]:SetText(Utility.toKMBString(tostring(v2)))
                else
                    self.stItemNum[k1]:SetText(tostring(v2))
                end
                self.stItemNum[k1]:SetVisible(true)
            end
        end
    end
end

function UIResultAward:endHideUI()
    -- LogUtil.log("--- endHideUI ---"..self.time)
    self.btnSure:SetVisible(false)
    self.stGetText:SetVisible(false)
    self.siBgEffec:SetVisible(false)
end

function UIResultAward:moveTitleAndItem(progress)
    self:moveUIByR_Area(self.siTitleBox, self.titleBoxR_star_Area, self.titleBoxR_end_Area, progress)
    self:moveUIByR_Area(self.siItemBox, self.itemBoxR_star_Area, self.itemBoxR_end_Area, progress)
end

function UIResultAward:showNextUI()
    self:hide()
    GUIResultRank:ShowResultRank(self.rankDate)
    GUIResultRank.setAlphaTime = GUIResultRank.alphaTime
    self.aniBegin = false
    GUIResultAward.iuStatus = Animation.beginShowUI.status
end

function UIResultAward:ShowResultAward(data)
    if not self:isLoad() then
        return
    end
    local builder = json.decode(data)
    self.rankDate[1] = builder[1].rank
    self.rankDate[2] = builder[2]
    self:setTitleText(builder[1].stage, builder[1].rank)
    self.numDate = builder[1]
    self:hideOtherWindow()
    self:show()
    self.aniBegin = true
    self.time = 0
    self.aniStatus = Animation.beginShowUI.status
end

function UIResultAward:setTitleText(stage, rank)
    -- LogUtil.log("--- setTitleText ---stage ： "..tostring(stage).." rank： "..tostring(rank))
    local lvConfig = self:getLvConfigByLv(stage)
    if lvConfig then
        local rankDes = tostring(lvConfig.seasonRankDes)
        self.stTitleText[1]:SetText(Lang:getString(rankDes))
    end
    self.stTitleText[2]:SetText(Lang:getString("Rank"))
    self.stTitleText[3]:SetText(tostring(rank))
end

function UIResultAward:getLvConfigByLv(lv)
    local lvConfig = GameConfig.championshipsLvConfig
    for _, info in pairs(lvConfig) do
        if tonumber(lv) >= tonumber(info.lvDown) and tonumber(lv) <= tonumber(info.lvUp) then
            -- LogUtil.log("--- getLvConfigByLv ---"..tostring(info))
            return info
        end
    end
    return nil
end

function UIResultAward:onClickSure()
    -- LogUtil.log("--- onClickSure ---")
    self.aniBegin = true
    if self.aniStatus ~= Animation.endHideUI.status then
        self.aniStatus = Animation.endHideUI.status
    end
end

function UIResultAward:hideOtherWindow()
    GUIManager:hideWindowByName("ToolBar.json")
    GUIManager:hideWindowByName("Main.json")
    GUIManager:hideWindowByName("Menu.json")
    GUIMainControl:hide()
    GUIMainControlTool:hide()
    GUIMainControlRank:hide()
    PlayerManager:getClientPlayer().property.canAttack = false
    PlayerManager:getClientPlayer().property.canWorkout = false
	CustomDialog.hide()
    GUIMainControlSettlement:hide()
    GUIWorkout:hide()
    GUINewGuide:hide()
    GUIShop:hide()
    GUIPayShop:hide()
    GUITip:hide()
end

function UIResultAward:moveUIByR_Area(UI, start_r_area, end_r_area, progress)
    local r_dy = (end_r_area.r_y - start_r_area.r_y) * progress + start_r_area.r_y
    UI:SetArea({start_r_area.r_x, 0 }, {r_dy, 0 }, {start_r_area.r_width, 0 }, {start_r_area.r_height, 0 })
end

function UIResultAward:getUIR_Area(UI)
    local Area = {}
    local area = UI:GetArea()
    Area = {r_x = area.min.x[1], r_y = area.min.y[1], r_width = area.max.x[1] - area.min.x[1], r_height = area.max.y[1] - area.min.y[1]}
    return Area
end

function UIResultAward:setUI_End_R_Area(area, dy)
    local Area = {}
    Area = {r_x = area.r_x, r_y = area.r_y + dy, r_width = area.r_width, r_height = area.r_height}
    return Area
end

return UIResultAward
